import React, { useEffect, useState } from "react";
import Fuse from "fuse.js";
import api from "../components/api";
import { IProduct } from "../types/types";
const PRODUCTS_TIME_KEY = "products_time";
const PRODUCTS_KEY = "products";

const fuseOptions = {
  isCaseSensitive: false,
  // includeScore: true,
  // shouldSort: true,
  // includeMatches: false,
  // findAllMatches: false,
  minMatchCharLength: 2,
  // location: 0,
  // threshold: 0.6,
  // distance: 100,
  // useExtendedSearch: false,
  // ignoreLocation: false,
  // ignoreFieldNorm: false,
  // fieldNormWeight: 1,
  keys: [
    {
      name: "name",
      weight: 0.5
    },
    {
      name: "categoryName",
      weight: 0.2
    },
    {
      name: "tagsName",
      weight: 0.2
    },
    {
      name: "genderName",
      weight: 0.1
    }
  ]
};
const fuse = new Fuse([], fuseOptions);

const updateSearchEngine = (products: any) => {
  fuse.setCollection(products);
};

const productsService = async (): Promise<IProduct[]> => {
  const response = await api.get("/v1/products");
  return response.data;
};

const useProducts = () => {

  useEffect(() => {
    const oldTime: number = parseInt(sessionStorage.getItem(PRODUCTS_TIME_KEY) || "");
    const now: number = Date.now();
    const exp = 10 * 1000 * 60; // 10 minutes
    if (!oldTime || now - oldTime > exp) {
      productsService().then((prods) => {
        StoreProducts.updateProducts(now, prods);
        updateSearchEngine(prods);
      }).catch((err) => {
        console.log(err);
      });
    } else {
      updateSearchEngine(StoreProducts.getProducts());
    }
  }, []);

  const searchProducts = (query: string) => {
    let searchRes;
    if (query) {
      const fuseRes = fuse.search(query);
      searchRes = fuseRes.map(result => result.item);
    } else {
      searchRes = StoreProducts.getProducts();
    }
    return searchRes;
  }

  return { searchProducts }
}
export default useProducts;


class StoreProducts {
  public static updateProducts(time: number, products: IProduct[]) {
    sessionStorage.setItem(PRODUCTS_TIME_KEY, time.toString());
    sessionStorage.setItem(PRODUCTS_KEY, JSON.stringify(products));
  }
  public static getProducts(): IProduct[] {
    const storedColors = sessionStorage.getItem(PRODUCTS_KEY);
    return storedColors ? JSON.parse(storedColors) : [];
  }
}
